	private static void assertPlannerCostInvariants(String plan, String key, double maxDirectLookupWorkRows) {
		assertTrue(plan.contains("plannerId=lmdb-sketch"), key + " should use LMDB sketch planning:\n" + plan);
		assertTrue(plan.contains("plannerPath=ROBUST_USED"), key + " should use the robust planner path:\n" + plan);
		assertFalse(plan.contains("plannerPath=UNSUPPORTED_SHAPE"),
				key + " should not reject supported segment shapes:\n" + plan);
		assertDirectLookupWorkRowsBelow(plan, key, maxDirectLookupWorkRows);
	}

	private static void assertCanonicalFiniteAnchorFastPath(String plan, String key) {
		assertTrue(plan.contains("plannerId=lmdb-finite-anchor")
				|| plan.contains("plannerPath=CANONICAL_FINITE_ANCHOR"),
				key + " should mark canonical finite-anchor planning:\n" + plan);
		assertFalse(plan.contains("plannerPath=ROBUST_USED"),
				key + " should keep the already finite-anchored chain out of robust sketch planning:\n" + plan);
		assertFalse(plan.contains("optimizer.logicalExploration"),
				key + " should not spend Pareto memo/beam work on a canonical finite-anchor chain:\n" + plan);
		assertPlanBefore(plan, key, "BindingSetAssignment ([[disease=http://example.com/theme/pharma/disease/0]",
				"value=http://example.com/theme/pharma/studiesDisease");
		assertPlanBefore(plan, key, "value=http://example.com/theme/pharma/studiesDisease",
				"value=http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
		assertPlanBefore(plan, key, "value=http://example.com/theme/pharma/hasArm",
				"value=http://example.com/theme/pharma/pValue");
	}

