	private static void loadData(SailRepository repository, Theme theme) throws IOException {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			RDFInserter inserter = new RDFInserter(connection);
			ThemeDataSetGenerator.generate(theme, inserter);
			connection.commit();
		}
	}

	private static void primePharmaFastestRunLearnedStats(SailRepository repository) {
		for (int queryIndex : List.of(0, 1)) {
			String query = ThemeQueryCatalog.queryFor(Theme.PHARMA, queryIndex);
			long expected = ThemeQueryCatalog.expectedCountFor(Theme.PHARMA, queryIndex);
			long actual = executeQuery(repository, query);
			if (actual != expected) {
				fail("Unable to prime learned filter stats for PHARMA:" + queryIndex + ": expected=" + expected
						+ ", actual=" + actual);
			}
		}
	}

	private static long executeQuery(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return connection.prepareTupleQuery(query)
					.evaluate()
					.stream()
					.count();
		}
	}

	private static OptimizerSnapshot explainOptimized(SailRepository repository, Theme theme, int queryIndex) {
		return explain(repository, theme, queryIndex, Explanation.Level.Optimized);
	}

	private static OptimizerSnapshot explain(SailRepository repository, Theme theme, int queryIndex,
			Explanation.Level level) {
		String query = ThemeQueryCatalog.queryFor(theme, queryIndex);
		try (SailRepositoryConnection connection = repository.getConnection()) {
			Explanation explanation = connection.prepareTupleQuery(query)
					.explain(level);
			return new OptimizerSnapshot(
					explanation.toString(),
					new TupleExprIRRenderer().render((TupleExpr) explanation.tupleExpr()));
		}
	}

	private static void assertPlanContains(String plan, String key, String... needles) {
		for (String needle : needles) {
			assertTrue(plan.contains(needle), key + " missing plan fragment: " + needle + "\n" + plan);
		}
	}

	private static void assertPlanBefore(String plan, String key, String before, String after) {
		int beforeIndex = plan.indexOf(before);
		int afterIndex = plan.indexOf(after);
		assertTrue(beforeIndex >= 0, key + " missing plan fragment: " + before + "\n" + plan);
		assertTrue(afterIndex >= 0, key + " missing plan fragment: " + after + "\n" + plan);
		assertTrue(beforeIndex < afterIndex,
				key + " expected " + before + " before " + after + "\n" + plan);
	}

	private static void assertSelectiveFilterPlan(String plan, String key, String filteredPattern, double minRatio,
			double maxRatio) {
		int patternIndex = plan.indexOf(filteredPattern);
		assertTrue(patternIndex >= 0, key + " missing filtered pattern: " + filteredPattern + "\n" + plan);

		int filterIndex = plan.lastIndexOf("Filter (", patternIndex);
		assertTrue(filterIndex >= 0, key + " should wrap " + filteredPattern + " in a planned filter:\n" + plan);

		int patternLineEnd = plan.indexOf('\n', patternIndex);
		String filterRegion = plan.substring(filterIndex, patternLineEnd >= 0 ? patternLineEnd : plan.length());
		Matcher ratioMatcher = FILTER_PASS_RATIO.matcher(filterRegion);
		assertTrue(ratioMatcher.find(),
				key + " should include a filter pass ratio for " + filteredPattern + ":\n" + plan);

		double ratio = Double.parseDouble(ratioMatcher.group(1));
		assertTrue(ratio >= minRatio && ratio <= maxRatio,
				key + " should apply the selective score filter before join-order scoring: " + filterRegion + "\n"
						+ plan);
	}

	private static void assertDirectLookupWorkRowsBelow(String plan, String key, double maxWorkRows) {
		Matcher matcher = DIRECT_LOOKUP_WORK_ROWS.matcher(plan);
		int directLookupCount = 0;
		while (matcher.find()) {
			directLookupCount++;
			double workRows = parsePlanRows(matcher.group(1));
			assertTrue(workRows <= maxWorkRows,
					key + " direct lookup plannedWorkRows should stay bounded by explicit step work, got "
							+ matcher.group(1) + "\n" + plan);
		}
		assertTrue(directLookupCount > 0, key + " should expose at least one direct lookup metric:\n" + plan);
	}

	private static double parsePlanRows(String value) {
		String trimmed = value.trim();
		double multiplier = 1.0d;
		if (trimmed.endsWith("K")) {
			multiplier = 1_000.0d;
			trimmed = trimmed.substring(0, trimmed.length() - 1);
		} else if (trimmed.endsWith("M")) {
			multiplier = 1_000_000.0d;
			trimmed = trimmed.substring(0, trimmed.length() - 1);
		} else if (trimmed.endsWith("B")) {
			multiplier = 1_000_000_000.0d;
			trimmed = trimmed.substring(0, trimmed.length() - 1);
		}
		return Double.parseDouble(trimmed) * multiplier;
	}

	private static void shutdownAndRelease(SailRepository repository, LmdbStore store) throws IOException {
		try {
			BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
		} finally {
			repository.shutDown();
		}
	}

